def pbkdf2_hash_password(password: str, salt: bytes = None, iterations: int = 200_000) -> str:
    if salt is None:
        salt = secrets.token_bytes(16)
    dk = hashlib.pbkdf2_hmac("sha256", password.encode("utf-8"), salt, iterations)
    return "pbkdf2_sha256$%d$%s$%s" % (
        iterations,
        base64.urlsafe_b64encode(salt).decode("utf-8").rstrip("="),
        base64.urlsafe_b64encode(dk).decode("utf-8").rstrip("="),
    )


def pbkdf2_verify_password(password: str, stored: str) -> bool:
    try:
        algo, iters_s, salt_b64, dk_b64 = stored.split("$", 3)
        if algo != "pbkdf2_sha256":
            return False
        iterations = int(iters_s)
        salt = base64.urlsafe_b64decode(salt_b64 + "==")
        expected = base64.urlsafe_b64decode(dk_b64 + "==")
        dk = hashlib.pbkdf2_hmac("sha256", password.encode("utf-8"), salt, iterations)
        return hmac.compare_digest(dk, expected)
    except Exception:
        return False


def b32_secret(nbytes: int = 20) -> str:
    return base64.b32encode(secrets.token_bytes(nbytes)).decode("utf-8").rstrip("=")


def totp_now(secret_b32: str, step: int = 30, digits: int = 6, t: int = None) -> str:
    if t is None:
        t = int(time.time())
    counter = int(t // step)
    key = base64.b32decode(secret_b32 + "=" * ((8 - (len(secret_b32) % 8)) % 8), casefold=True)
    msg = counter.to_bytes(8, "big")
    hm = hmac.new(key, msg, hashlib.sha1).digest()
    offset = hm[-1] & 0x0F
    code_int = (int.from_bytes(hm[offset:offset + 4], "big") & 0x7FFFFFFF) % (10 ** digits)
    return str(code_int).zfill(digits)


def totp_verify(secret_b32: str, code: str, window: int = 1, step: int = 30, digits: int = 6) -> bool:
    code = (code or "").strip().replace(" ", "")
    if not code.isdigit():
        return False
    t = int(time.time())
    for w in range(-window, window + 1):
        if hmac.compare_digest(totp_now(secret_b32, step=step, digits=digits, t=t + w * step), code):
            return True
    return False


def sign_token(payload: dict) -> str:
    body = json.dumps(payload, separators=(",", ":"), sort_keys=True).encode("utf-8")
    body_b64 = base64.urlsafe_b64encode(body).decode("utf-8").rstrip("=")
    sig = hmac.new(APP_SECRET.encode("utf-8"), body_b64.encode("utf-8"), hashlib.sha256).digest()
    sig_b64 = base64.urlsafe_b64encode(sig).decode("utf-8").rstrip("=")
    return f"{body_b64}.{sig_b64}"


def verify_signed_token(token: str) -> dict | None:
    try:
        body_b64, sig_b64 = token.split(".", 1)
        sig = base64.urlsafe_b64decode(sig_b64 + "==")
        expected = hmac.new(APP_SECRET.encode("utf-8"), body_b64.encode("utf-8"), hashlib.sha256).digest()
        if not hmac.compare_digest(sig, expected):
            return None
        body = base64.urlsafe_b64decode(body_b64 + "==")
        payload = json.loads(body.decode("utf-8"))
        return payload
    except Exception:
        return None


def token_hash(token: str) -> str:
    return hashlib.sha256(token.encode("utf-8")).hexdigest()


