@app.post("/register")
@require_json
def register():
    data = request.get_json(silent=True) or {}
    email = normalize_email(data.get("email"))
    password = data.get("password") or ""
    if not email or "@" not in email:
        return jsonify({"error": "Invalid email"}), 400
    if len(password) < 8:
        return jsonify({"error": "Password must be at least 8 characters"}), 400

    db = get_db()
    existing = get_user_by_email(email)
    if existing:
        return jsonify({"error": "Email already registered"}), 409

    ph = pbkdf2_hash_password(password)
    ts = utc_iso(now_utc())
    db.execute(
        "INSERT INTO users (email, password_hash, mfa_enabled, mfa_secret, created_at, updated_at) VALUES (?, ?, 0, NULL, ?, ?)",
        (email, ph, ts, ts),
    )
    db.commit()
    return jsonify({"ok": True})


@app.post("/login")
@require_json
def login():
    data = request.get_json(silent=True) or {}
    email = normalize_email(data.get("email"))
    password = data.get("password") or ""
    mfa_code = data.get("mfa_code")

    user = get_user_by_email(email)
    if not user or not pbkdf2_verify_password(password, user["password_hash"]):
        return jsonify({"error": "Invalid credentials"}), 401

    if int(user["mfa_enabled"]) == 1:
        if not user["mfa_secret"]:
            return jsonify({"error": "MFA misconfigured; contact support"}), 403
        if not mfa_code or not totp_verify(user["mfa_secret"], str(mfa_code)):
            return jsonify({"error": "MFA required", "mfa_required": True}), 401

    session_payload = {"sub": user["id"], "email": user["email"], "iat": int(time.time())}
    session_token = sign_token(session_payload)
    return jsonify({"ok": True, "session_token": session_token, "mfa_enabled": bool(user["mfa_enabled"])})


def auth_user():
    auth = request.headers.get("Authorization", "")
    if not auth.startswith("Bearer "):
        return None
    token = auth.split(" ", 1)[1].strip()
    payload = verify_signed_token(token)
    if not payload or "sub" not in payload:
        return None
    user = get_user_by_id(int(payload["sub"]))
    return user


def require_auth(f):
    @wraps(f)
    def wrapper(*args, **kwargs):
        user = auth_user()
        if not user:
            return jsonify({"error": "Unauthorized"}), 401
        g.current_user = user
        return f(*args, **kwargs)
    return wrapper


