@app.post("/reset-mfa")
@require_json
def reset_mfa_request():
    data = request.get_json(silent=True) or {}
    email = normalize_email(data.get("email"))
    if not email or "@" not in email:
        return jsonify({"ok": True}), 200

    user = get_user_by_email(email)
    if not user:
        return jsonify({"ok": True}), 200

    raw = secrets.token_urlsafe(32)
    payload = {"typ": "mfa_reset", "uid": int(user["id"]), "exp": int(time.time()) + RESET_TOKEN_TTL_SECONDS, "nonce": secrets.token_hex(8)}
    signed = sign_token(payload)
    combined = f"{raw}.{signed}"
    th = token_hash(combined)

    created = utc_iso(now_utc())
    expires = utc_iso(now_utc() + timedelta(seconds=RESET_TOKEN_TTL_SECONDS))

    db = get_db()
    db.execute(
        "INSERT INTO mfa_reset_tokens (user_id, token_hash, created_at, expires_at, used_at) VALUES (?, ?, ?, ?, NULL)",
        (user["id"], th, created, expires),
    )
    db.commit()

    if BASE_URL:
        link = BASE_URL.rstrip("/") + url_for("reset_mfa_confirm", token=combined)
    else:
        link = url_for("reset_mfa_confirm", token=combined, _external=True)

    subject = "MFA reset link"
    body = (
        f"We received a request to reset MFA for your account.\n\n"
        f"If you initiated this request, click the link below to disable MFA and log in with password only:\n\n"
        f"{link}\n\n"
        f"This link expires in {RESET_TOKEN_TTL_SECONDS // 60} minutes.\n"
        f"If you did not request this, you can ignore this email.\n"
    )
    send_email(user["email"], subject, body)

    return jsonify({"ok": True})


@app.get("/reset-mfa/confirm")
def reset_mfa_confirm():
    token = request.args.get("token", "").strip()
    if not token or "." not in token:
        return jsonify({"error": "Invalid token"}), 400

    th = token_hash(token)
    db = get_db()
    row = db.execute("SELECT * FROM mfa_reset_tokens WHERE token_hash = ?", (th,)).fetchone()
    if not row:
        return jsonify({"error": "Invalid or expired token"}), 400
    if row["used_at"] is not None:
        return jsonify({"error": "Token already used"}), 400

    try:
        expires_at = datetime.fromisoformat(row["expires_at"].replace("Z", ""))
    except Exception:
        return jsonify({"error": "Invalid token state"}), 400
    if now_utc() > expires_at:
        return jsonify({"error": "Invalid or expired token"}), 400

    try:
        raw, signed = token.split(".", 1)
    except Exception:
        return jsonify({"error": "Invalid token"}), 400

    payload = verify_signed_token(signed)
    if not payload or payload.get("typ") != "mfa_reset":
        return jsonify({"error": "Invalid token"}), 400
    if int(payload.get("exp", 0)) < int(time.time()):
        return jsonify({"error": "Invalid or expired token"}), 400

    uid = int(payload.get("uid", 0))
    if uid != int(row["user_id"]):
        return jsonify({"error": "Invalid token"}), 400

    user = get_user_by_id(uid)
    if not user:
        return jsonify({"error": "Invalid token"}), 400

    ts = utc_iso(now_utc())
    db.execute(
        "UPDATE users SET mfa_enabled = 0, mfa_secret = NULL, updated_at = ? WHERE id = ?",
        (ts, uid),
    )
    db.execute(
        "UPDATE mfa_reset_tokens SET used_at = ? WHERE id = ?",
        (ts, row["id"]),
    )
    db.commit()

    return jsonify({"ok": True, "message": "MFA has been reset. You can now log in with password only."})


